// // This comment suggests that the counter decrements on the rising edge of clk when en is high.
module binary_counter(
	input wire clk,
	input wire reset,
	input wire en,
	output reg [3:0] count
);always @(posedge clk or posedge reset) begin
		if (reset)
			count <= 4'b0000;
		else if (en)
			count <= count + 1;
	end
endmodule
